import pdfMakeRaw from 'pdfmake/build/pdfmake';

// ──────────────────────────────────────────────────────────────
// FORCE TRUE SINGLETON USING GLOBAL (works even with Vite duplication)
// ──────────────────────────────────────────────────────────────
declare global {
  interface Window {
    __PDFMAKE_INSTANCE__?: typeof pdfMakeRaw;
  }
}

const pdfMake = ((): typeof pdfMakeRaw => {
  if (typeof window !== 'undefined' && (window as any).__PDFMAKE_INSTANCE__) {
    console.log('Reusing existing pdfMake instance');
    return (window as any).__PDFMAKE_INSTANCE__;
  }

  console.log('Creating new pdfMake instance with Indian fonts');

  // === YOUR FULL VFS (Roboto + Indian fonts) ===
  const vfs: Record<string, string> = {
    // Roboto (must be included — copy from vfs_fonts.js)
    // 'Roboto-Regular.ttf': 'AAEAAAAOAACWAIAAAABk...',         // get from https://github.com/bpampuch/pdfmake/blob/master/build/vfs_fonts.js
    "Roboto-Regular.ttf": "",
    // 'Roboto-Medium.ttf': 'AAEAAAAkAA...',
    "Roboto-Medium.ttf": "",
    "Roboto-Italic.ttf": "",

    // 'Roboto-Italic.ttf': 'AAEAAAAcAA...',
    // 'Roboto-MediumItalic.ttf': 'AAEAAAAgAA...',
      "Roboto-MediumItalic.ttf": "",


    // Your Indian fonts
    // 'NotoSansDevanagari-Regular.ttf': 'AAEAAAAQAQAABAAAR0RFRiLPGhsAAAI8AAADCkdQT1NaLT/cAA…RNTgWCRI2ORYAAAEAKAJeAVECpQADAABBFSE1AVH+1wKlR0c=',
 
    'NotoSansDevanagari-Regular.ttf':'',
    'NotoSansTamil-Regular.ttf':'',
    'MuktaVaani-Regular.ttf':''

};

  pdfMakeRaw.addVirtualFileSystem(vfs);

  pdfMakeRaw.fonts = {
    Roboto: {
      normal: 'Roboto-Regular.ttf',
      bold: 'Roboto-Medium.ttf',
      italics: 'Roboto-Italic.ttf',
      bolditalics: 'Roboto-MediumItalic.ttf',
    },
    NotoSansDevanagari: {
      normal: 'NotoSansDevanagari-Regular.ttf',
      bold: 'NotoSansDevanagari-Regular.ttf',
      italics: 'NotoSansDevanagari-Regular.ttf',
      bolditalics: 'NotoSansDevanagari-Regular.ttf',
    },
    NotoSansTamil: {
      normal: 'NotoSansTamil-Regular.ttf',
      bold: 'NotoSansTamil-Regular.ttf',
      italics: 'NotoSansTamil-Regular.ttf',
      bolditalics: 'NotoSansTamil-Regular.ttf',
    },
    MuktaVaani: {
      normal: 'MuktaVaani-Regular.ttf',
      bold: 'MuktaVaani-Regular.ttf',
      italics: 'MuktaVaani-Regular.ttf',
      bolditalics: 'MuktaVaani-Regular.ttf',
    },
  };

  // Your table layouts
  pdfMakeRaw.tableLayouts = {
    prescriptionTableLayout: {
      hLineWidth: (i: number, node: any) => (i === 0 || i === node.table.body.length) ? 0.8 : 0.3,
      vLineWidth: () => 0.1,
      hLineColor: () => '#333333',
      vLineColor: () => '#cccccc',
      paddingLeft: () => 4,
      paddingRight: () => 4,
      paddingTop: () => 4,
      paddingBottom: () => 4,
    },
    noBorders: {
      hLineWidth: () => 0,
      vLineWidth: () => 0,
    },
  };

  // Save to global
  if (typeof window !== 'undefined') {
    (window as any).__PDFMAKE_INSTANCE__ = pdfMakeRaw;
  }

  return pdfMakeRaw;
})();

export default pdfMake